	(6, 11, '+Juego Nuevo', NULL, '', 'https://img.psnprofiles.com/game/m/13714/944b5e7b-93b9-4b76-92ce-a3adce0800ea.png', 'https://4kwallpapers.com/images/wallpapers/ghost-of-tsushima-3840x2160-12072.jpg', '4 sobre 10', '', 0, 1, 1, 0, 0, 0, '', 0, 0, NULL, '2026-06-19 09:10:22'),
	(8, 16, 'Assassin`s Creed Valhalla - La Ira de los Druidas', '2021-05-13', '', 'https://image.api.playstation.com/vulcan/ap/rnd/202103/2216/XZbdgeMJ5j2d23kXFDg1at2A.png?w=440&thumb=false', 'https://image.api.playstation.com/vulcan/img/rnd/202105/1316/O5oCvLXM2j56DqbwhsuqrLu9.jpg?w=2048&thumb=false', '5 sobre 10', '', 0, 0, 9, 0, 0, 0, '', 0, 0, NULL, '2026-06-20 21:33:58'),
