	(171, 4, 'A Nuestra Pequeña Familia', 'Completa el episodio 6: Crisálida.', 'BRONCE', 1, 0, 0, 'https://img.psnprofiles.com/trophy/m/34699/8ad7de46-afb9-4e80-9862-cf24c3931d74.png', 'Trofeo parte de la historia.', ''),
	(172, 4, 'El Pobre Sam No Tiene Ni Idea', 'Completa el episodio 7: Cápsula.', 'BRONCE', 1, 0, 0, 'https://img.psnprofiles.com/trophy/m/34699/0c516905-ec38-4758-8ae8-68332071cec9.png', 'Trofeo parte de la historia.', ''),
