	(174, 4, 'No soy tan Frágil', 'Completa el episodio 9: Marioneta.', 'BRONCE', 1, 0, 0, 'https://img.psnprofiles.com/trophy/m/34699/a697b6b0-575c-4776-a802-79fc3fc12888.png', 'Trofeo parte de la historia.', ''),
